class QtInfo(object):
    def __init__(self, qmake_command=None):
        if qmake_command:
            self._qmake_command = qmake_command
        else:
            self._qmake_command = [find_executable("qmake"),]
        self._dict = {}
        # bind all variables early at __init__ time.
        for thing in self.__class__.__dict__:
            getattr(self, thing)
